"""Final-surface narrative consolidation without changing faithfulness verdicts."""
from __future__ import annotations

from collections import Counter
import logging
import re
from typing import Any, Sequence

from src.polaris_graph.settings import resolve

_OFF = frozenset({"", "0", "false", "no", "off", "disabled"})
_CITATION_RE = re.compile(r"\[\d+\]")
logger = logging.getLogger("polaris_graph.narrative_consolidation")

# A sentence boundary is deliberately conservative: a terminator must be followed by the
# end of the text or whitespace and an uppercase/opening character.  Fixed-width negative
# lookbehinds protect common abbreviations and initials; the digit checks protect decimals.
_SENTENCE_RE = re.compile(
    r".*?(?:"
    r"(?:(?<!\b(?i:et\ al))(?<!\b(?i:e\.g))(?<!\b(?i:i\.e))"
    r"(?<!\b(?i:vs))(?<!\b(?i:fig))(?<!\b(?i:no))(?<!\b(?i:dr))"
    r"(?<!\b(?i:mr))(?<!\b(?i:ms))(?<!\b(?i:mrs))(?<!\b(?i:prof))"
    r"(?<!\b(?i:eq))(?<!\b(?i:inc))(?<!\b(?i:ltd))(?<!\b(?i:u\.s))"
    r"(?<!\b(?i:u\.k))(?<!\b[A-Z])"
    r"(?<!\d)\.(?!\d)|[!?])"
    r"[)\]}\"'\u2019\u201d]*(?:\s*\[\d+\])*"
    r"(?=\s+(?:[*_]*[A-Z]|[(\[{\"'\u2018\u201c]\s*[*_]*[A-Z])|\s*$)"
    r"|$)",
    re.DOTALL,
)


def enabled() -> bool:
    return (resolve("PG_NARRATIVE_CONSOLIDATION") or "").strip().lower() not in _OFF


def thread_narrative_guidance(plans: Sequence[Any]) -> None:
    """Ask the verified writer for cited relational transitions before generation."""
    if not enabled():
        return
    guidance = (
        "Use cohesive scholarly prose. For adjacent cited findings, explicitly explain with their "
        "citations why they agree, differ, or condition one another; emphasize the key finding or "
        "term with Markdown bold; describe evidence limitations through publication type, "
        "representativeness, and risk of bias rather than implementation vocabulary."
    )
    for plan in plans:
        plan.focus = f"{plan.focus.rstrip()} {guidance}"


def _signature(sentence: str) -> str:
    """Return exact normalized prose, excluding citation markers only."""
    plain = _CITATION_RE.sub(" ", sentence)
    plain = " ".join(plain.split())
    return re.sub(r"\s+([.!?])", r"\1", plain)


def _citations(text: str) -> list[str]:
    return _CITATION_RE.findall(text)


def _sentence_spans(text: str) -> list[tuple[str, int, int]]:
    """Return conservative full-sentence spans without separator whitespace."""
    spans: list[tuple[str, int, int]] = []
    for match in _SENTENCE_RE.finditer(text):
        raw = match.group(0)
        sentence = raw.strip()
        if not sentence:
            continue
        start = match.start() + len(raw) - len(raw.lstrip())
        end = match.end() - (len(raw) - len(raw.rstrip()))
        spans.append((sentence, start, end))
    return spans


def _sentence_text_multiset(texts: Sequence[str]) -> Counter[str]:
    return Counter(
        signature
        for text in texts
        for sentence, _, _ in _sentence_spans(text)
        if (signature := _signature(sentence))
    )


def _merge_citations(sentence: str, markers: Sequence[str]) -> str:
    """Combine markers while preserving every non-citation byte of the kept sentence."""
    inserted = False

    def replace_marker(_: re.Match[str]) -> str:
        nonlocal inserted
        if inserted:
            return ""
        inserted = True
        return "".join(markers)

    return _CITATION_RE.sub(replace_marker, sentence)


def _apply_sentence_edits(text: str, edits: Sequence[tuple[int, int, str]]) -> str:
    for start, end, replacement in sorted(edits, reverse=True):
        text = f"{text[:start]}{replacement}{text[end:]}"
    return text


def consolidate_sections(sections: Sequence[Any]) -> dict[str, Any]:
    """Mutate rendered section text, merging exact repeated findings into one statement.

    The canonical statement receives every citation occurrence from every repeated instance.
    Distinct wording is never clustered, so qualifiers and conditions remain separate. If the
    report-wide citation or sentence-text multiset changes unexpectedly, all section text is
    restored. Only complete sentences with identical normalized prose can be removed.
    """
    if not enabled():
        return {}
    active = [
        section for section in sections
        if not getattr(section, "dropped_due_to_failure", False)
        and not getattr(section, "is_gap_stub", False)
        and str(getattr(section, "verified_text", "") or "").strip()
    ]
    originals = {id(section): section.verified_text for section in active}
    before = Counter(marker for section in active for marker in _citations(section.verified_text))
    occurrences: dict[str, list[tuple[Any, str, int, int]]] = {}
    for section in active:
        text = section.verified_text
        if "|" in text:
            continue
        for sentence, start, end in _sentence_spans(text):
            if not _citations(sentence) or "\n#" in sentence:
                continue
            signature = _signature(sentence)
            if signature:
                occurrences.setdefault(signature, []).append((section, sentence, start, end))

    consolidated = 0
    removed_texts: Counter[str] = Counter()
    edits: dict[int, list[tuple[int, int, str]]] = {id(section): [] for section in active}
    for signature, group in occurrences.items():
        if len({id(item[0]) for item in group}) < 2:
            continue
        canonical_section, canonical_sentence, canonical_start, canonical_end = max(
            group, key=lambda item: (len(_citations(item[1])), -list(active).index(item[0]), -item[2])
        )
        all_markers = [marker for _, sentence, _, _ in group for marker in _citations(sentence)]
        edits[id(canonical_section)].append(
            (canonical_start, canonical_end, _merge_citations(canonical_sentence, all_markers))
        )
        canonical_used = False
        for section, sentence, start, end in group:
            if (
                section is canonical_section
                and start == canonical_start
                and sentence == canonical_sentence
                and not canonical_used
            ):
                canonical_used = True
                continue
            edits[id(section)].append((start, end, ""))
            removed_texts[signature] += 1
            consolidated += 1

    for section in active:
        section.verified_text = _apply_sentence_edits(
            originals[id(section)], edits[id(section)]
        )

    after = Counter(marker for section in active for marker in _citations(section.verified_text))
    input_texts = _sentence_text_multiset(list(originals.values()))
    expected_texts = input_texts.copy()
    expected_texts.subtract(removed_texts)
    expected_texts += Counter()
    output_texts = _sentence_text_multiset(
        [section.verified_text for section in active]
    )
    try:
        if after != before:
            raise AssertionError("citation multiset changed")
        if output_texts != expected_texts:
            raise AssertionError("sentence-text multiset changed")
    except AssertionError as exc:
        for section in active:
            section.verified_text = originals[id(section)]
        logger.warning(
            "Narrative consolidation reverted because a preservation assertion failed: %s",
            exc,
        )
        return {
            "consolidated": 0,
            "consolidation_applied": False,
            "reverted": True,
            "evidence_multiset_preserved": after == before,
            "text_multiset_preserved": output_texts == expected_texts,
        }
    return {
        "consolidated": consolidated,
        "consolidation_applied": consolidated > 0,
        "evidence_multiset_preserved": True,
        "text_multiset_preserved": True,
    }

"""Structural acceptance guard for Markdown passed through benchmark cleaning."""
from __future__ import annotations

from dataclasses import dataclass
import re
from typing import Sequence

from src.polaris_graph.settings import resolve

_OFF = frozenset({"", "0", "false", "no", "off", "disabled"})
_SEPARATOR_CELL_RE = re.compile(r"^:?-{3,}:?$")


@dataclass(frozen=True)
class TableDefect:
    line_number: int
    reason: str


def enabled() -> bool:
    return (resolve("PG_CLEANED_OUTPUT_GUARD") or "").strip().lower() not in _OFF


def _cells(line: str) -> list[str]:
    return [cell.strip() for cell in line.strip().strip("|").split("|")]


def find_malformed_tables(markdown: str) -> list[TableDefect]:
    lines = markdown.splitlines()
    defects: list[TableDefect] = []
    in_table = False
    width = 0
    for position, line in enumerate(lines):
        stripped = line.strip()
        if position + 1 < len(lines) and "|" in stripped:
            separator = _cells(lines[position + 1])
            if separator and all(_SEPARATOR_CELL_RE.match(cell) for cell in separator):
                width = len(_cells(stripped))
                in_table = True
                if len(separator) != width:
                    defects.append(TableDefect(position + 2, "separator_width"))
                continue
        if not in_table:
            continue
        if not stripped:
            in_table = False
            width = 0
            continue
        if not stripped.startswith("|"):
            defects.append(TableDefect(position + 1, "multiline_cell"))
            in_table = False
            width = 0
            continue
        if len(_cells(stripped)) != width:
            defects.append(TableDefect(position + 1, "row_width"))
    return defects


def _table_to_prose(lines: Sequence[str]) -> str:
    rows = [_cells(line) for line in lines if "|" in line]
    if len(rows) < 2:
        return " ".join(line.strip() for line in lines if line.strip())
    headers = rows[0]
    data = [row for row in rows[2:] if len(row) == len(headers)]
    sentences: list[str] = []
    for row in data:
        parts = [f"{header}: {value}" for header, value in zip(headers, row) if header and value]
        if parts:
            sentences.append("; ".join(parts) + ".")
    continuation = [line.strip() for line in lines if "|" not in line and line.strip()]
    return " ".join(sentences + continuation)


def repair_for_cleaning(markdown: str) -> tuple[str, list[TableDefect]]:
    if not enabled():
        return markdown, []
    defects = find_malformed_tables(markdown)
    if not defects:
        return markdown, []
    lines = markdown.splitlines()
    output: list[str] = []
    position = 0
    while position < len(lines):
        if position + 1 < len(lines) and "|" in lines[position]:
            separator = _cells(lines[position + 1])
            if separator and all(_SEPARATOR_CELL_RE.match(cell) for cell in separator):
                block = [lines[position], lines[position + 1]]
                position += 2
                while position < len(lines) and lines[position].strip():
                    block.append(lines[position])
                    position += 1
                if find_malformed_tables("\n".join(block)):
                    output.append(_table_to_prose(block))
                else:
                    output.extend(block)
                continue
        output.append(lines[position])
        position += 1
    repaired = "\n".join(output)
    remaining = find_malformed_tables(repaired)
    if remaining:
        raise ValueError(f"cleaned-output guard could not repair malformed tables: {remaining}")
    return repaired, defects

"""Instruction-gated citation planning over a retained, unmodified corpus."""
from __future__ import annotations

from dataclasses import dataclass, field
import logging
import re
from typing import Any, Mapping, Sequence
from urllib.parse import urlsplit

from src.polaris_graph.settings import resolve
from src.polaris_graph.retrieval.rq_eligibility import (
    _admitted_genres,
    _parse_recency_bounds,
    _row_genre,
    _row_language,
    _row_year,
    detect_language_offline,
)
from src.polaris_graph.retrieval.document_type_classifier import DocumentType

_OFF = frozenset({"", "0", "false", "no", "off", "disabled"})
logger = logging.getLogger("polaris_graph.exclusive_citation_eligibility")
_EXCLUSIVE_RE = re.compile(
    r"\b(?:only|exclusively|restricted\s+to|limited\s+to|must\s+(?:all\s+)?be|do\s+not\s+(?:use|cite))\b",
    re.IGNORECASE,
)

# These are publication-surface classes, not journal-name allowlists.  They are deliberately
# conservative: a known repository/working-paper/news/blog surface vetoes every positive signal.
_PREPRINT_OR_WORKING_PAPER_HOSTS = frozenset({
    "arxiv.org", "ssrn.com", "nber.org", "preprints.org", "researchsquare.com",
    "biorxiv.org", "medrxiv.org", "osf.io", "psyarxiv.com", "researchgate.net",
    "academia.edu",
})
_NON_JOURNAL_HOSTS = _PREPRINT_OR_WORKING_PAPER_HOSTS | frozenset({
    "medium.com", "substack.com", "wordpress.com", "blogspot.com",
})
_NON_JOURNAL_DOI_REGISTRANTS = frozenset({
    "10.1101",   # bioRxiv / medRxiv
    "10.1109",   # mixed IEEE journal/conference registrant; DOI alone is ambiguous
    "10.1145",   # ACM proceedings-heavy registrant
    "10.17605",  # OSF
    "10.2139",   # SSRN
    "10.3386",   # NBER working papers
    "10.48550",  # arXiv
    "10.5061",   # Dryad datasets
    "10.5281",   # Zenodo repository records
    "10.6084",   # Figshare repository records
    "10.7910",   # Dataverse datasets
})
_NON_JOURNAL_TEXT_RE = re.compile(
    r"\b(?:pre[ -]?print|working[ -]?paper|discussion[ -]?paper|policy[ -]?brief|"
    r"press[ -]?release|government[ -]?report|white[ -]?paper|news(?:letter)?|blog)\b",
    re.IGNORECASE,
)
_CHROME_TITLE_RE = re.compile(
    r"^(?:just a moment|error\b|access denied|page not found|cookies? (?:are )?(?:disabled|turned off))",
    re.IGNORECASE,
)
_DOI_RE = re.compile(r"\b(10\.\d{4,9})/[\w.()/:+-]+", re.IGNORECASE)

# Generic article-route shapes used by journal platforms.  No venue or task names are encoded.
_JOURNAL_ARTICLE_URL_RES = tuple(re.compile(pattern, re.IGNORECASE) for pattern in (
    r"/articles/pmc\d+/?$",
    r"/science/article/pii/",
    r"/journals?/[^?#]*/articles?/",
    r"/article/10\.\d{4,9}/",
    r"/doi/(?:abs/|full/|pdf/|epdf/)?10\.\d{4,9}/",
    r"/core/journals/[^/]+/article/",
    r"/(?:ojs/)?index\.php/[^/]+/article/(?:view|download)/",
    r"/article/\d+/\d+/",
    r"/article/(?:view|download)/\d+",
    r"/content/\d+/\d+/",
))
_JOURNAL_HOST_LABEL_RE = re.compile(r"^(?:journal|journals)[.-]", re.IGNORECASE)
_JOURNAL_VENUE_RE = re.compile(r"\b(?:journal|review|quarterly)\b", re.IGNORECASE)
_VOLUME_ISSUE_RE = re.compile(
    r"\b(?:vol(?:ume)?\.?\s*\d+\s*[,;:]?\s*(?:no\.?|issue)\s*\d+|\d+\s*\(\s*\d+\s*\))\b",
    re.IGNORECASE,
)


@dataclass
class CitationEligibilityPlan:
    active: bool = False
    body_evidence: list[dict[str, Any]] = field(default_factory=list)
    disclosed_evidence: list[dict[str, Any]] = field(default_factory=list)
    backfills: list[dict[str, str]] = field(default_factory=list)


def enabled() -> bool:
    return (resolve("PG_EXCLUSIVE_CITATION_ELIGIBILITY") or "").strip().lower() not in _OFF


def has_explicit_exclusive_constraint(prompt: str, constraints: Mapping[str, Any] | None) -> bool:
    if not constraints or not _EXCLUSIVE_RE.search(prompt or ""):
        return False
    return bool(
        constraints.get("source_types")
        or constraints.get("languages")
        or constraints.get("recency")
        or constraints.get("exclusions")
    )


def _host(row: Mapping[str, Any]) -> str:
    url = str(row.get("source_url") or row.get("url") or "")
    try:
        return (urlsplit(url).hostname or "").lower()
    except ValueError:
        return ""


def _host_in(host: str, choices: frozenset[str]) -> bool:
    return any(host == item or host.endswith("." + item) for item in choices)


def known_non_journal_surface(row: Mapping[str, Any]) -> bool:
    """Return True only for an affirmative offline non-journal surface signal."""
    host = _host(row)
    if _host_in(host, _NON_JOURNAL_HOSTS):
        return True
    text = " ".join(str(row.get(key) or "") for key in (
        "title", "source_url", "url", "source_class", "document_type",
    ))
    if _NON_JOURNAL_TEXT_RE.search(text):
        return True
    doi_match = _DOI_RE.search(" ".join(str(row.get(key) or "") for key in (
        "doi", "source_url", "url",
    )))
    return bool(doi_match and doi_match.group(1).lower() in _NON_JOURNAL_DOI_REGISTRANTS)


def known_preprint_or_working_paper_host(row: Mapping[str, Any]) -> bool:
    """Return True for a recognized preprint/repository/working-paper hostname."""
    return _host_in(_host(row), _PREPRINT_OR_WORKING_PAPER_HOSTS)


def _unknown_row_has_journal_signal(row: Mapping[str, Any]) -> bool:
    """Conservative positive classifier for otherwise-UNKNOWN rows; pure and offline."""
    if known_non_journal_surface(row):
        return False
    title = str(row.get("title") or "").strip()
    if not title or _CHROME_TITLE_RE.search(title):
        return False
    url = str(row.get("source_url") or row.get("url") or "")
    host = _host(row)

    # A resolvable DOI is affirmative publication metadata unless its registrant/surface is one of
    # the explicit repository and working-paper classes vetoed above.
    if _DOI_RE.search(" ".join((str(row.get("doi") or ""), url))):
        return True
    if any(pattern.search(url) for pattern in _JOURNAL_ARTICLE_URL_RES):
        return True
    if _JOURNAL_HOST_LABEL_RE.search(host + ".") and "/article" in url.lower():
        return True

    venue = " ".join(str(row.get(key) or "") for key in ("journal", "venue"))
    publication = " ".join((title, venue, str(row.get("citation") or "")))
    return bool(
        _JOURNAL_VENUE_RE.search(venue)
        and _VOLUME_ISSUE_RE.search(publication)
    )


def _eligible(row: Mapping[str, Any], constraints: Mapping[str, Any]) -> tuple[bool, list[str]]:
    reasons: list[str] = []
    source_types = [str(item) for item in constraints.get("source_types", [])]
    admitted = _admitted_genres(source_types)
    if admitted is not None:
        genre = _row_genre(row)
        if genre == DocumentType.UNKNOWN and row.get("document_type"):
            try:
                genre = DocumentType(str(row.get("document_type")).strip().upper())
            except ValueError:
                pass
        if genre == DocumentType.UNKNOWN and _unknown_row_has_journal_signal(row):
            genre = DocumentType.JOURNAL_ARTICLE
        if admitted.issubset({DocumentType.JOURNAL_ARTICLE, DocumentType.REVIEW_ARTICLE}) \
                and known_non_journal_surface(row):
            # An explicit repository/working-paper/conference/dataset surface wins even over a
            # stale positive document_type stamp.  The published manifestation can still enter via
            # the same-work replacement path below; the non-journal manifestation cannot be cited.
            genre = DocumentType.PREPRINT
        if genre not in admitted:
            reasons.append("document_type")
    languages = [str(item).strip().lower()[:2] for item in constraints.get("languages", [])]
    if languages:
        language = _row_language(row)
        if language is None:
            language = detect_language_offline(" ".join(
                str(row.get(key) or "")
                for key in ("title", "snippet", "abstract", "statement", "direct_quote")
            ))
        # Missing/ambiguous language metadata is not evidence of a mismatch.  Reject only a
        # positively identified language outside the explicit allow-set.
        if language is not None and language not in languages:
            reasons.append("language")
    floor, ceiling = _parse_recency_bounds(constraints.get("recency"))
    if floor is not None or ceiling is not None:
        year = _row_year(row)
        if year is None or (floor is not None and year < floor) or (ceiling is not None and year > ceiling):
            reasons.append("recency")
    return not reasons, reasons


def _group_members(
    groups: Sequence[Mapping[str, Any]] | None,
    rows: Sequence[Mapping[str, Any]],
) -> dict[str, set[str]]:
    by_member: dict[str, set[str]] = {}
    for group in groups or []:
        members = {str(item) for item in group.get("member_evidence_ids", []) if str(item)}
        for member in members:
            by_member.setdefault(member, set()).update(members)
    # Composition rows can carry the same resolver result inline after canonicalization.  Consult
    # that representation too, rather than depending on the optional top-level group payload.
    for row in rows:
        evidence_id = str(row.get("evidence_id") or "")
        members = {
            str(item)
            for item in row.get("same_work_member_evidence_ids", []) or []
            if str(item)
        }
        if evidence_id:
            members.add(evidence_id)
        if len(members) > 1:
            for member in members:
                by_member.setdefault(member, set()).update(members)
    return by_member


def _title_key(row: Mapping[str, Any]) -> str:
    return re.sub(r"[^\w]+", " ", str(row.get("title") or "").casefold()).strip()


def plan_citation_eligibility(
    *,
    prompt: str,
    constraints: Mapping[str, Any] | None,
    evidence: Sequence[Mapping[str, Any]],
    same_work_groups: Sequence[Mapping[str, Any]] | None = None,
) -> CitationEligibilityPlan:
    original = [dict(row) for row in evidence]
    if not enabled() or not has_explicit_exclusive_constraint(prompt, constraints):
        return CitationEligibilityPlan(active=False, body_evidence=original)
    rules = dict(constraints or {})
    rows_by_id = {str(row.get("evidence_id") or ""): row for row in original}
    eligible_ids = {
        evidence_id for evidence_id, row in rows_by_id.items()
        if evidence_id and _eligible(row, rules)[0]
    }
    member_groups = _group_members(same_work_groups, original)
    eligible_by_title: dict[str, str] = {}
    for evidence_id in eligible_ids:
        key = _title_key(rows_by_id[evidence_id])
        if key:
            eligible_by_title.setdefault(key, evidence_id)

    selected: list[dict[str, Any]] = []
    selected_ids: set[str] = set()
    disclosed: list[dict[str, Any]] = []
    backfills: list[dict[str, str]] = []
    for row in original:
        evidence_id = str(row.get("evidence_id") or "")
        ok, reasons = _eligible(row, rules)
        replacement = ""
        if not ok:
            candidates = member_groups.get(evidence_id, set())
            replacement = next((item for item in sorted(candidates) if item in eligible_ids), "")
            if not replacement:
                replacement = eligible_by_title.get(_title_key(row), "")
        chosen_id = evidence_id if ok else replacement
        if chosen_id and chosen_id not in selected_ids and chosen_id in rows_by_id:
            selected.append(dict(rows_by_id[chosen_id]))
            selected_ids.add(chosen_id)
        if not ok:
            disclosed.append({
                "evidence_id": evidence_id,
                "title": str(row.get("title") or ""),
                "source_url": str(row.get("source_url") or row.get("url") or ""),
                "reasons": reasons,
                "statement": str(row.get("statement") or row.get("direct_quote") or ""),
                "eligible_same_work_evidence_id": replacement or None,
            })
            if replacement:
                backfills.append({"from_evidence_id": evidence_id, "to_evidence_id": replacement})
    logger.info(
        "[citation_eligibility] admitted=%d disclosed=%d backfilled=%d retained_corpus=%d",
        len(selected), len(disclosed), len(backfills), len(original),
    )
    return CitationEligibilityPlan(
        active=True,
        body_evidence=selected,
        disclosed_evidence=disclosed,
        backfills=backfills,
    )

"""Semantic coverage obligations carried from prompt constraints to report assembly."""
from __future__ import annotations

from dataclasses import asdict, dataclass
import re
from typing import Any, Mapping, Sequence

from src.polaris_graph.settings import resolve

_OFF = frozenset({"", "0", "false", "no", "off", "disabled"})
_ROLES = ("frame", "mechanism", "cross-context comparison", "synthesis", "implication")
_WORD_RE = re.compile(r"[^\W_]+", re.UNICODE)


@dataclass(frozen=True)
class CoverageObligation:
    concept: str
    role: str
    comparative: bool = False


def enabled() -> bool:
    return (resolve("PG_COVERAGE_OBLIGATIONS") or "").strip().lower() not in _OFF


def _role_for(concept: str, position: int) -> str:
    text = concept.lower()
    if re.search(r"\b(various|across|between|different|multiple)\b", text):
        return "cross-context comparison"
    if re.search(r"\b(mechanism|how|why|driver|pathway|process)\b", text):
        return "mechanism"
    if re.search(r"\b(frame|context|era|revolution|paradigm)\b", text):
        return "frame"
    if re.search(r"\b(implication|recommendation|policy|future|consequence)\b", text):
        return "implication"
    if re.search(r"\b(overall|synthesis|integrat|conclusion)\b", text):
        return "synthesis"
    return _ROLES[position % len(_ROLES)]


def build_obligations(required_coverage: Sequence[str] | None) -> list[CoverageObligation]:
    obligations: list[CoverageObligation] = []
    seen: set[str] = set()
    for position, raw in enumerate(required_coverage or []):
        concept = " ".join(str(raw).split()).strip()
        key = concept.casefold()
        if not concept or key in seen:
            continue
        seen.add(key)
        role = _role_for(concept, position)
        obligations.append(CoverageObligation(
            concept=concept,
            role=role,
            comparative=(role == "cross-context comparison"),
        ))
    return obligations


def thread_obligations(plans: Sequence[Any], obligations: Sequence[CoverageObligation]) -> None:
    """Attach each obligation to an outline focus and repeat the full spine in the conclusion."""
    if not enabled() or not plans or not obligations:
        return
    for position, obligation in enumerate(obligations):
        plan = plans[position % len(plans)]
        direction = (
            "develop one explicit cross-context comparative unit"
            if obligation.comparative else f"treat it analytically as a {obligation.role}"
        )
        plan.focus = (
            f"{plan.focus.rstrip()} Coverage obligation: connect {obligation.concept!r} to the cited "
            f"evidence and {direction}."
        )
    conclusion = next(
        (plan for plan in reversed(plans) if re.search(r"conclu|synth|implication", plan.title, re.I)),
        plans[-1],
    )
    spine = "; ".join(f"{item.concept} ({item.role})" for item in obligations)
    conclusion.focus = (
        f"{conclusion.focus.rstrip()} In the closing synthesis, reconnect the supported findings to "
        f"these prompt obligations: {spine}."
    )


def audit_fulfillment(
    obligations: Sequence[CoverageObligation],
    sections: Sequence[Any],
) -> dict[str, Any]:
    bodies = [str(getattr(section, "verified_text", "") or "") for section in sections]
    joined = " ".join(bodies).casefold()
    missing: list[dict[str, Any]] = []
    fulfilled: list[dict[str, Any]] = []
    for obligation in obligations:
        tokens = [token.casefold() for token in _WORD_RE.findall(obligation.concept)]
        present = bool(tokens) and all(token in joined for token in tokens)
        record = asdict(obligation)
        (fulfilled if present else missing).append(record)
    return {"fulfilled": fulfilled, "missing": missing}


def render_sections_preserving_outline(
    outline: Sequence[Any],
    sections: Sequence[Any],
) -> tuple[list[str], list[str]]:
    """Render every planned heading; a missing result becomes an explicit non-claim disclosure."""
    remaining = list(sections)
    rendered: list[str] = []
    disclosed: list[str] = []
    for plan in outline:
        match = next((section for section in remaining if section.title == plan.title), None)
        if match is not None:
            remaining.remove(match)
        if match is not None and not match.dropped_due_to_failure and match.verified_text:
            rendered.append(f"## {match.title}\n\n{match.verified_text}")
            continue
        title = str(getattr(plan, "title", "") or "Planned section")
        rendered.append(
            f"## {title}\n\nThe planned analysis could not be rendered from the available "
            "citation-eligible verified evidence; the gap is disclosed rather than silently omitted."
        )
        disclosed.append(title)
    for section in remaining:
        if not section.dropped_due_to_failure and section.verified_text:
            rendered.append(f"## {section.title}\n\n{section.verified_text}")
    return rendered, disclosed


def required_coverage_from(constraints: Mapping[str, Any] | None) -> list[str]:
    if not isinstance(constraints, Mapping):
        return []
    return [str(item) for item in constraints.get("required_coverage", []) if str(item).strip()]

